import{_ as e,c as l,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Agent Skills 入門: 擴展 AI 代理能力 | Agent Skills","description":"了解 Agent Skills，學會擴展 Claude、Cursor 等 AI 代理的技能包。本教學介紹 React 效能優化、Web 設計指南和一鍵部署功能，提升開發效率。","frontmatter":{"title":"Agent Skills 入門: 擴展 AI 代理能力 | Agent Skills","sidebarTitle":"入門","subtitle":"Agent Skills 入門: 擴展 AI 代理能力","description":"了解 Agent Skills，學會擴展 Claude、Cursor 等 AI 代理的技能包。本教學介紹 React 效能優化、Web 設計指南和一鍵部署功能，提升開發效率。","tags":["入門","AI 編碼代理","Claude","技能包"],"prerequisite":[]},"headers":[],"relativePath":"zh-tw/vercel-labs/agent-skills/start/getting-started/index.md","filePath":"zh-tw/vercel-labs/agent-skills/start/getting-started/index.md"}'),s={name:"zh-tw/vercel-labs/agent-skills/start/getting-started/index.md"};function r(o,t,d,n,c,h){return a(),l("div",null,[...t[0]||(t[0]=[i(`<h1 id="agent-skills-入門" tabindex="-1">Agent Skills 入門 <a class="header-anchor" href="#agent-skills-入門" aria-label="Permalink to &quot;Agent Skills 入門&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>理解 Agent Skills 是什麼，以及它如何擴展 AI 編碼代理的能力</li><li>了解三大核心技能包的功能和使用場景</li><li>知道什麼時候適合使用 Agent Skills 來提升開發效率</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你日常使用 Claude、Cursor 或其他 AI 編碼代理時，可能會遇到這些問題：</p><ul><li>希望遵循最佳實踐，但不知道該記住哪些規則</li><li>經常重複類似的部署操作，希望自動化</li><li>AI 生成的程式碼品質參差不齊，缺少統一標準</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>Agent Skills 是技能包系統</strong>——為 AI 編碼代理提供可擴展的「外掛」。每個技能包含：</p><ul><li><strong>SKILL.md</strong>：技能定義文件，告訴 AI 代理什麼時候啟用該技能</li><li><strong>scripts/</strong>：輔助腳本（如部署腳本），執行具體任務</li><li><strong>references/</strong>：輔助文件（選用），提供詳細參考資料</li></ul><div class="tip custom-block"><p class="custom-block-title">設計理念</p><p>技能採用<strong>按需載入</strong>機制：只有技能名稱和描述在啟動時載入，完整內容在 AI 判斷需要時才讀取。這樣可以減少上下文佔用，提高效率。</p></div><h2 id="可用的技能包" tabindex="-1">可用的技能包 <a class="header-anchor" href="#可用的技能包" aria-label="Permalink to &quot;可用的技能包&quot;">​</a></h2><p>專案提供三大技能包，每個都針對特定場景：</p><h3 id="react-best-practices" tabindex="-1">react-best-practices <a class="header-anchor" href="#react-best-practices" aria-label="Permalink to &quot;react-best-practices&quot;">​</a></h3><p>React 和 Next.js 效能優化指南，來自 Vercel Engineering 標準。包含 50+ 條規則，按影響層級排序。</p><p><strong>使用場景</strong>：</p><ul><li>編寫新的 React 元件或 Next.js 頁面</li><li>審查程式碼效能問題</li><li>優化打包大小或載入時間</li></ul><p><strong>覆蓋類別</strong>：</p><ul><li>消除瀑布</li><li>打包大小優化</li><li>伺服器端效能</li><li>客戶端資料獲取</li><li>Re-render 優化</li><li>渲染效能</li><li>JavaScript 微優化</li><li>高級模式</li></ul><h3 id="web-design-guidelines" tabindex="-1">web-design-guidelines <a class="header-anchor" href="#web-design-guidelines" aria-label="Permalink to &quot;web-design-guidelines&quot;">​</a></h3><p>Web 介面設計指南審計，檢查程式碼是否符合近百條最佳實踐。</p><p><strong>使用場景</strong>：</p><ul><li>提示詞：&quot;Review my UI&quot;</li><li>檢查可訪問性</li><li>審計設計一致性</li><li>檢查效能和 UX</li></ul><p><strong>覆蓋類別</strong>：</p><ul><li>可訪問性（aria-labels、語義化 HTML、鍵盤處理）</li><li>Focus 狀態（可見焦點、focus-visible 模式）</li><li>表單（自動完成、驗證、錯誤處理）</li><li>動畫（prefers-reduced-motion、合成友好的變換）</li><li>圖片（尺寸、懶載入、alt 文字）</li><li>排版、效能、導航等</li></ul><h3 id="vercel-deploy-claimable" tabindex="-1">vercel-deploy-claimable <a class="header-anchor" href="#vercel-deploy-claimable" aria-label="Permalink to &quot;vercel-deploy-claimable&quot;">​</a></h3><p>一鍵部署應用和網站到 Vercel，返回預覽連結和所有權轉移連結。</p><p><strong>使用場景</strong>：</p><ul><li>提示詞：&quot;Deploy my app&quot;</li><li>快速分享專案預覽</li><li>無需配置，零認證部署</li></ul><p><strong>核心特性</strong>：</p><ul><li>自動檢測 40+ 種框架（Next.js、Vite、Astro 等）</li><li>返回預覽 URL（即時站點）和 claim URL（轉移所有權）</li><li>自動處理靜態 HTML 專案</li><li>上傳時排除 <code>node_modules</code> 和 <code>.git</code></li></ul><h2 id="技能的工作原理" tabindex="-1">技能的工作原理 <a class="header-anchor" href="#技能的工作原理" aria-label="Permalink to &quot;技能的工作原理&quot;">​</a></h2><p>當你使用 Claude 或其他 AI 代理時，技能啟用流程如下：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[使用者輸入任務] --&gt; B[AI 檢測關鍵詞&lt;br/&gt;如 Deploy, Review, Optimize]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[匹配技能描述]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[載入 SKILL.md 完整內容]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[執行腳本或應用規則]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[輸出結果給使用者]</span></span></code></pre></div><p><strong>示例流程</strong>：</p><ol><li><strong>使用者輸入</strong>：&quot;Deploy my app&quot;</li><li><strong>AI 檢測</strong>：識別關鍵詞 &quot;Deploy&quot;，匹配 <code>vercel-deploy</code> 技能</li><li><strong>載入技能</strong>：讀取 <code>SKILL.md</code> 完整內容</li><li><strong>執行部署</strong>： <ul><li>執行 <code>deploy.sh</code> 腳本</li><li>檢測框架（讀取 package.json）</li><li>打包專案為 tarball</li><li>上傳到 Vercel API</li></ul></li><li><strong>返回結果</strong>：<div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;previewUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://skill-deploy-abc123.vercel.app&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;claimUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://vercel.com/claim-deployment?code=...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li></ol><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p>使用 Agent Skills 的最佳時機：</p><table tabindex="0"><thead><tr><th>場景</th><th>使用的技能</th><th>觸發提示詞示例</th></tr></thead><tbody><tr><td>編寫 React 元件</td><td>react-best-practices</td><td>&quot;Review this React component for performance issues&quot;</td></tr><tr><td>優化 Next.js 頁面</td><td>react-best-practices</td><td>&quot;Help me optimize this Next.js page&quot;</td></tr><tr><td>檢查 UI 品質</td><td>web-design-guidelines</td><td>&quot;Check accessibility of my site&quot;</td></tr><tr><td>部署專案</td><td>vercel-deploy-claimable</td><td>&quot;Deploy my app to production&quot;</td></tr></tbody></table><h2 id="安全模型" tabindex="-1">安全模型 <a class="header-anchor" href="#安全模型" aria-label="Permalink to &quot;安全模型&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">安全說明</p><ul><li><strong>本機執行</strong>：所有技能在本機執行，無資料上傳至第三方服務（Vercel 部署 API 除外）</li><li><strong>按需啟用</strong>：技能僅在 AI 判斷相關時載入詳細內容，減少隱私洩漏風險</li><li><strong>開源透明</strong>：所有技能和腳本開源可審計</li></ul></div><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="技能未啟用" tabindex="-1">技能未啟用 <a class="header-anchor" href="#技能未啟用" aria-label="Permalink to &quot;技能未啟用&quot;">​</a></h3><p>如果技能沒有被啟用，檢查：</p><ul><li>提示詞是否包含足夠的關鍵詞（如 &quot;Deploy&quot;、&quot;Review&quot;）</li><li>技能是否正確安裝到 <code>~/.claude/skills/</code> 目錄</li><li>如果使用 claude.ai，確認技能已新增到專案知識庫</li></ul><h3 id="網路權限" tabindex="-1">網路權限 <a class="header-anchor" href="#網路權限" aria-label="Permalink to &quot;網路權限&quot;">​</a></h3><p>某些技能需要網路存取：</p><ul><li><code>vercel-deploy-claimable</code> 需要存取 Vercel 部署 API</li><li><code>web-design-guidelines</code> 需要從 GitHub 拉取最新規則</li></ul><p><strong>解決方案</strong>：在 claude.ai/settings/capabilities 中新增所需網域。</p><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>Agent Skills 是為 AI 編碼代理設計的技能包系統，提供：</p><ul><li><strong>react-best-practices</strong>：50+ 條 React/Next.js 效能優化規則</li><li><strong>web-design-guidelines</strong>：近百條 Web 設計最佳實踐</li><li><strong>vercel-deploy-claimable</strong>：一鍵部署到 Vercel</li></ul><p>技能採用按需載入機制，減少上下文佔用。安裝後，AI 代理會自動在相關任務中啟用對應的技能。</p><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們將學習 <strong><a href="./../installation/">安裝 Agent Skills</a></strong>。</p><p>你將學到：</p><ul><li>兩種安裝方法：Claude Code 和 claude.ai</li><li>配置網路權限</li><li>驗證技能是否正確安裝</li></ul></blockquote><hr><h2 id="附錄-源碼參考" tabindex="-1">附錄：源碼參考 <a class="header-anchor" href="#附錄-源碼參考" aria-label="Permalink to &quot;附錄：源碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看源碼位置</strong></summary><blockquote><p>更新時間：2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>技能包列表</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L7-L80" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>7-80</td></tr><tr><td>技能結構說明</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L103-L110" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>103-110</td></tr><tr><td>AGENTS.md 規範</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>全文</td></tr><tr><td>技能目錄結構</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L11-L20" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>11-20</td></tr><tr><td>SKILL.md 格式</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L29-L68" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>29-68</td></tr><tr><td>技能打包命令</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L93-L96" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>93-96</td></tr><tr><td>使用者安裝方法</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L98-L110" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>98-110</td></tr><tr><td>按需載入機制</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L72-L78" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>72-78</td></tr><tr><td>建構工具腳本</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/package.json" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/package.json</code></a></td><td>全文</td></tr></tbody></table><p><strong>關鍵常量</strong>：</p><ul><li>無硬編碼常量</li></ul><p><strong>關鍵函數</strong>：</p><ul><li><code>build.ts</code>：建構 AGENTS.md 和測試用例</li><li><code>validate.ts</code>：驗證規則檔案完整性</li><li><code>extract-tests.ts</code>：從規則中提取測試用例</li></ul></details>`,57)])])}const u=e(s,[["render",r]]);export{g as __pageData,u as default};
